{
  "name": "Alabama Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "None",
    "asset_limits": "None",
    "other_requirements": ["Must be a resident of a long-term care facility such as nursing home, assisted living facility, specialty care facility, or boarding home (personal care home). Services also available to family, friends, or facility employees on behalf of residents."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigate and resolve complaints about poor patient care, quality of care, facility structure issues; provide direct client advocacy; conduct quarterly/routine visitations to facilities to monitor conditions and talk to residents; mediate between residents, families, and staff; educate on residents' rights, facility selection, eligibility criteria, and other elderly services; protect rights to dignity, freedom from restraints, voice grievances, private communication, confidential records, fair treatment, advance notice of transfer/discharge; advocate for systemic changes at local/state/national levels.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 334-242-5753 or 1-800-AGE-LINE (1-800-243-5463)", "In writing", "In person", "Email: info@EastAlabamaAging.org (for East Alabama region inquiries)"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["Complaints may be filed in writing, by phone, or in person; no specific form name/number identified"],
    "documents": ["None required; complainants do not have to give their name; all information is confidential"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services targeted to residents of long-term care facilities across Alabama",
    "regional_variations": "Administered statewide by Alabama Department of Senior Services (ADSS) with at least one community ombudsman per area agency on aging planning and service area (13 areas with 20.30 certified ombudsmen total); local area agencies (e.g., East Alabama Aging, Aging South Alabama) handle regional ombudsman services, but core services consistent statewide",
    "offices_or_providers": ["State Office: Alabama Department of Senior Services, Virginia Moore-Bell, Director (334-242-5753)", "Area Agencies on Aging (e.g., East Alabama Aging, Aging South Alabama)"]
  },
  "official_source": "https://alabamaageline.gov/ombudsman/",
  "gotchas": ["Not a direct service provider (e.g., no healthcare, financial aid, or personal care services)—purely advocacy and complaint resolution; no financial eligibility barriers, but must involve a long-term care facility resident; confidential but can be filed anonymously; ombudsmen are trained/certified advocates without facility conflicts; volunteers support but report to certified community ombudsmen"],
  "data_shape_notes": "no income/asset/age test; advocacy-only for long-term care facility residents statewide via ADSS and 13 area agencies on aging; open to anyone filing on behalf of resident"
}

{
  "name": "Senior Aides Program",
  "eligibility": {
    "age": null,
    "income_limits": "No specific 'Senior Aides Program' found in Alabama search results. Closest matches are Elderly & Disabled (E&D) Waiver (income up to $2,982/month per applicant in 2026, regardless of marital status) or Alabama CARES (income not a barrier, prioritizes greatest needs).[1][3]",
    "asset_limits": "For E&D Waiver: Standard Medicaid asset limits apply (exact $ amount not specified); exempt: primary home, household furnishings, appliances, personal effects, one vehicle. 60-month look-back rule for transfers.[1]",
    "other_requirements": ["No exact match for 'Senior Aides Program'. Possible confusion with E&D Waiver (age 65+ or disabled, nursing facility level of care via HCBS-1 assessment, meet 2/11 criteria like ADL needs), Personal Choices (self-direction under HCBS waivers), or Alabama CARES (caregivers of 60+, dementia patients, or relative caregivers 55+ for children/disabled adults).[1][3][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "No specific details for 'Senior Aides Program'. E&D Waiver: Home/community-based services to avoid nursing home. Personal Choices: Self-direct personal care, respite, etc. Alabama CARES: Information, support, training, personal care, adult day care, homemaker services (no fixed $ or hours specified).[1][3][5][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["For E&D/Personal Choices: Local Area Agency on Aging at 1-877-425-2243; Alabama CARES: 1-800-AGE-LINE (1-800-243-5463) or local AAA/ADRC; Medicaid general: medicaid.alabama.gov applications/forms.[3][4][7]"],
    "processing_time": "Not specified in results",
    "waitlist": "Not specified; waivers often have waitlists (inferred, not direct)",
    "forms": ["HCBS-1 for E&D level of care; general E&D applications on medicaid.alabama.gov.[1][4]"],
    "documents": ["Income/asset proof, medical/functional assessments; veterans must apply for max benefits.[1][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Statewide via local AAAs for most programs",
    "regional_variations": "Administered by local Area Agencies on Aging (AAAs); contact varies by waiver/provider (e.g., ADSS for ACT, DRS for SAIL).[3][7]",
    "offices_or_providers": ["Local AAA at 1-877-425-2243; Alabama Age Line 1-800-243-5463.[3][7]"]
  },
  "official_source": "https://medicaid.alabama.gov (for E&D/Personal Choices); https://alabamaageline.gov (CARES)",
  "gotchas": ["No program named 'Senior Aides Program' identified—may be misnomer for E&D Waiver aides, Personal Choices family payment, or state aides via AAAs. Dementia diagnosis alone insufficient for E&D. 60-month look-back penalties. Must meet NFLOC. Programs prioritize highest need.[1][3][7]"],
  "data_shape_notes": "No direct match; data fragmented across Medicaid E&D Waivers (financial/medical tests), CARES (caregiver support, no income test), Personal Choices (self-direction add-on). Regional AAA delivery; waitlists common for waivers."
}
